def foobar(n: int) -> str:
    """
    Returns 'Foo' for multiples of 2, 'Bar' for multiples of 7, 'FooBar' for multiples of both, or the number as a string otherwise.
    """
    if n % 2 == 0 and n % 7 == 0:
        return "FooBar"
    elif n % 2 == 0:
        return "Foo"
    elif n % 7 == 0:
        return "Bar"
    else:
        return str(n)
