def fib_seq(n: int) -> list:
    """Returns the first n numbers of a Fibonacci-like sequence Lucas-like starting from 2, 1.
    For example, fib_seq(5) should return [2, 1, 3, 4, 7].
    """
    if n <= 0:
        return []
    elif n == 1:
        return [2]
    else:
        list_fib = [2, 1]
        while len(list_fib) < n:
            next_fib = list_fib[-1] + list_fib[-2]
            list_fib.append(next_fib)
        return list_fib
