def fib_seq(n: int) -> list:
    """Returns the first n numbers of a Fibonacci-like sequence starting from 3, 5.
    For example, fib_seq(5) should return [3, 5, 8, 13, 21].
    """
    if n <= 0:
        return []
    elif n == 1:
        return [3]
    elif n == 2:
        return [3, 5]
    else:
        sequence = [3, 5]
        for i in range(2, n):
            next_num = sequence[-1] + sequence[-2]
            sequence.append(next_num)
        return sequence
