def fact(numb: int) -> int:
    """Compute factorial of a non-negative integer using recursion."""
    if numb < 0:
        raise ValueError("Factorial is not defined for negative numbers")

    if numb == 0 or numb == 1:
        return 1
    else:
        rslt: int = numb * fact(numb - 1)
        return rslt
